DYNAMODB_TABLE = os.environ.get("DYNAMODB_TABLE", "microservices-data")
S3_BUCKET = os.environ.get("S3_BUCKET", "")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
SQS_QUEUE_URL = os.environ.get("SQS_QUEUE_URL", "")


# ---- AWS Client Factory (Shared across microservices) ----
class AWSClientFactory:
    """
    Singleton-style client factory that all microservice Lambda functions
    can use. Clients are cached to reuse connections across invocations.
    All clients automatically use the shared IAM role permissions.
    """

    _clients: Dict[str, Any] = {}

    @classmethod
    def get_client(cls, service_name: str, region: Optional[str] = None):
        region = region or os.environ.get("AWS_REGION", "us-east-1")
        cache_key = f"{service_name}_{region}"
        if cache_key not in cls._clients:
            cls._clients[cache_key] = boto3.client(service_name, region_name=region)
        return cls._clients[cache_key]

    @classmethod
    def get_resource(cls, service_name: str, region: Optional[str] = None):
        region = region or os.environ.get("AWS_REGION", "us-east-1")
        cache_key = f"{service_name}_resource_{region}"
        if cache_key not in cls._clients:
            cls._clients[cache_key] = boto3.resource(service_name, region_name=region)
        return cls._clients[cache_key]


# ---- Service Helpers Using Shared IAM Role Permissions ----
class DynamoDBService:
    """DynamoDB operations - permissions granted by SharedDynamoDBAccess policy."""

    def __init__(self, table_name: str = DYNAMODB_TABLE):
        self.table_name = table_name
        self.client = AWSClientFactory.get_client("dynamodb")
        self.resource = AWSClientFactory.get_resource("dynamodb")
        self.table = self.resource.Table(table_name)

    def get_item(self, key: Dict) -> Optional[Dict]:
        try:
            response = self.table.get_item(Key=key)
            return response.get("Item")
        except ClientError as e:
            logger.error(f"DynamoDB GetItem error: {e.response['Error']['Message']}")
            raise

    def put_item(self, item: Dict) -> Dict:
        try:
            item["updated_at"] = datetime.now(timezone.utc).isoformat()
            item["service_name"] = SERVICE_NAME
            response = self.table.put_item(Item=item)
            logger.info(f"DynamoDB PutItem success for table {self.table_name}")
            return response
        except ClientError as e:
            logger.error(f"DynamoDB PutItem error: {e.response['Error']['Message']}")
            raise

    def update_item(self, key: Dict, update_expression: str,
                    expression_values: Dict, condition_expression: Optional[str] = None) -> Dict:
        try:
            params = {
                "Key": key,
                "UpdateExpression": update_expression,
                "ExpressionAttributeValues": expression_values,
                "ReturnValues": "ALL_NEW"
            }
            if condition_expression:
                params["ConditionExpression"] = condition_expression
            response = self.table.update_item(**params)
            return response.get("Attributes", {})
        except ClientError as e:
            logger.error(f"DynamoDB UpdateItem error: {e.response['Error']['Message']}")
            raise

    def query_items(self, key_condition_expression, expression_values: Dict,
                    index_name: Optional[str] = None, limit: int = 100) -> list:
        try:
            params = {
                "KeyConditionExpression": key_condition_expression,
                "ExpressionAttributeValues": expression_values,
                "Limit": limit
            }
            if index_name:
                params["IndexName"] = index_name
            response = self.table.query(**params)
            return response.get("Items", [])
        except ClientError as e:
            logger.error(f"DynamoDB Query error: {e.response['Error']['Message']}")
            raise

    def delete_item(self, key: Dict) -> Dict:
        try:
            response = self.table.delete_item(Key=key)
            logger.info(f"DynamoDB DeleteItem success for key {key}")
            return response
        except ClientError as e:
            logger.error(f"DynamoDB DeleteItem error: {e.response['Error']['Message']}")
            raise


class S3Service:
    """S3 operations - permissions granted by SharedS3Access policy."""

    def __init__(self, bucket_name: str = S3_BUCKET):
        self.bucket_name = bucket_name
        self.client = AWSClientFactory.get_client("s3")

    def get_object(self, key: str) -> bytes:
        try:
            response = self.client.get_object(Bucket=self.bucket_name, Key=key)
            return response["Body"].read()
        except ClientError as e:
            logger.error(f"S3 GetObject error for {key}: {e.response['Error']['Message']}")
            raise

    def put_object(self, key: str, body: bytes, content_type: str = "application/json",
                   metadata: Optional[Dict] = None) -> Dict:
        try:
            params = {
                "Bucket": self.bucket_name,
                "Key": key,
                "Body": body,
                "ContentType": content_type,
                "Metadata": metadata or {"service": SERVICE_NAME}
            }
            response = self.client.put_object(**params)
            logger.info(f"S3 PutObject success for {key} in {self.bucket_name}")
            return response
        except ClientError as e:
            logger.error(f"S3 PutObject error for {key}: {e.response['Error']['Message']}")
            raise

    def delete_object(self, key: str) -> Dict:
        try:
            response = self.client.delete_object(Bucket=self.bucket_name, Key=key)
            logger.info(f"S3 DeleteObject success for {key}")
            return response
        except ClientError as e:
            logger.error(f"S3 DeleteObject error for {key}: {e.response['Error']['Message']}")
            raise

    def list_objects(self, prefix: str, max_keys: int = 1000) -> list:
        try:
            response = self.client.list_objects_v2(
                Bucket=self.bucket_name,
                Prefix=prefix,
                MaxKeys=max_keys
            )
            return response.get("Contents", [])
        except ClientError as e:
            logger.error(f"S3 ListObjects error: {e.response['Error']['Message']}")
            raise

    def object_exists(self, key: str) -> bool:
        try:
            self.client.head_object(Bucket=self.bucket_name, Key=key)
            return True
        except ClientError:
            return False


class SNSService:
    """SNS operations - permissions granted by SharedSNSAccess policy."""

    def __init__(self, topic_arn: str = SNS_TOPIC_ARN):
        self.topic_arn = topic_arn
        self.client = AWSClientFactory.get_client("sns")

    def publish(self, message: Dict, subject: Optional[str] = None,
                message_attributes: Optional[Dict] = None) -> str:
        try:
            params = {
                "TopicArn": self.topic_arn,
                "Message": json.dumps(message),
            }
            if subject:
                params["Subject"] = subject
            if message_attributes:
                params["MessageAttributes"] = message_attributes
            else:
                params["MessageAttributes"] = {
                    "service_name": {
                        "DataType": "String",
                        "StringValue": SERVICE_NAME
                    },
                    "environment": {
                        "DataType": "String",
                        "StringValue": ENVIRONMENT
                    },
                    "timestamp": {
                        "DataType": "String",
                        "StringValue": datetime.now(timezone.utc).isoformat()
                    }
                }
            response = self.client.publish(**params)
            message_id = response["MessageId"]
            logger.info(f"SNS publish success: MessageId={message_id}")
            return message_id
        except ClientError as e:
            logger.error(f"SNS Publish error: {e.response['Error']['Message']}")
            raise

    def publish_to_topic(self, topic_arn: str, message: Dict,
                         subject: Optional[str] = None) -> str:
        try:
            params = {
                "TopicArn": topic_arn,
                "Message": json.dumps(message)
            }
            if subject:
                params["Subject"] = subject
            response = self.client.publish(**params)
            return response["MessageId"]
        except ClientError as e:
            logger.error(f"SNS Publish error: {e.response['Error']['Message']}")
            raise


class SQSService:
    """SQS operations - permissions granted by SharedSQSAccess policy."""

    def __init__(self, queue_url: str = SQS_QUEUE_URL):
        self.queue_url = queue_url
        self.client = AWSClientFactory.get_client("sqs")

    def send_message(self, message_body: Dict, delay_seconds: int = 0,
                     message_attributes: Optional[Dict] = None,
                     message_group_id: Optional[str] = None) -> str:
        try:
            params = {
                "QueueUrl": self.queue_url,
                "MessageBody": json.dumps(message_body),
                "DelaySeconds": delay_seconds,
                "MessageAttributes": message_attributes or {
                    "service_name": {
                        "DataType": "String",
                        "StringValue": SERVICE_NAME
                    }
                }
            }
            if message_group_id:
                params["MessageGroupId"] = message_group_id
            response = self.client.send_message(**params)
            message_id = response["MessageId"]
            logger.info(f"SQS send success: MessageId={message_id}")
            return message_id
        except ClientError as e:
            logger.error(f"SQS SendMessage error: {e.response['Error']['Message']}")
            raise

    def receive_messages(self, max_messages: int = 10, wait_time: int = 5,
                         visibility_timeout: int = 30) -> list:
        try:
            response = self.client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=max_messages,
                WaitTimeSeconds=wait_time,
                VisibilityTimeout=visibility_timeout,
                MessageAttributeNames=["All"]
            )
            return response.get("Messages", [])
        except ClientError as e:
            logger.error(f"SQS ReceiveMessage error: {e.response['Error']['Message']}")
            raise

    def delete_message(self, receipt_handle: str) -> Dict:
        try:
            response = self.client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle
            )
            logger.info("SQS delete message success")
            return response
        except ClientError as e:
            logger.error(f"SQS DeleteMessage error: {e.response['Error']['Message']}")
            raise

    def send_to_queue(self, queue_url: str, message_body: Dict,
                      delay_seconds: int = 0) -> str:
        try:
            response = self.client.send_message(
                QueueUrl=queue_url,
                MessageBody=json.dumps(message_body),
                DelaySeconds=delay_seconds
            )
            return response["MessageId"]
        except ClientError as e:
            logger.error(f"SQS SendMessage error: {e.response['Error']['Message']}")
            raise


# ---- Decorator for Standardized Lambda Handler Wrapping ----
def microservice_handler(service_name: str = SERVICE_NAME):
    """
    Decorator that wraps Lambda handlers with:
    - Structured logging
    - Error handling
    - Execution time tracking
    - Consistent response formatting

    All wrapped functions leverage the shared IAM role.
    """
    def decorator(func):
        @wraps(func)
        def wrapper(event, context):
            start_time = time.time()
            request_id = getattr(context, "aws_request_id", "unknown")
            function_name = getattr(context, "function_name", "unknown")

            logger.info(json.dumps({
                "level": "INFO",
                "message": "Lambda invocation started",
                "service": service_name,
                "function_name": function_name,
                "request_id": request_id,
                "shared_role": SHARED_ROLE_ARN,
                "event_source": _detect_event_source(event),
                "timestamp": datetime.now(timezone.utc).isoformat()
            }))

            try:
                result = func(event, context)
                duration = (time.time() - start_time) * 1000

                logger.info(json.dumps({
                    "level": "INFO",
                    "message": "Lambda invocation completed",
                    "service": service_name,
                    "function_name": function_name,
                    "request_id": request_id,
                    "duration_ms": round(duration, 2),
                    "status": "success"
                }))

                return result

            except ClientError as e:
                duration = (time.time() - start_time) * 1000
                error_code = e.response["Error"]["Code"]
                error_message = e.response["Error"]["Message"]

                logger.error(json.dumps({
                    "level": "ERROR",
                    "message": "AWS API error",
                    "service": service_name,
                    "function_name": function_name,
                    "request_id": request_id,
                    "duration_ms": round(duration, 2),
                    "error_code": error_code,
                    "error_message": error_message,
                    "traceback": traceback.format_exc()
                }))

                return _build_error_response(
                    status_code=_aws_error_to_http_status(error_code),
                    message=f"AWS service error: {error_message}",
                    request_id=request_id
                )

            except Exception as e:
                duration = (time.time() - start_time) * 1000

                logger.error(json.dumps({
                    "level": "ERROR",
                    "message": "Unhandled exception",
                    "service": service_name,
                    "function_name": function_name,
                    "request_id": request_id,
                    "duration_ms": round(duration, 2),
                    "error_type": type(e).__name__,
                    "error_message": str(e),
                    "traceback": traceback.format_exc()
                }))

                return _build_error_response(
                    status_code=500,
                    message="Internal server error",
                    request_id=request_id
                )

        return wrapper
    return decorator


# ---- Utility Functions ----
def _detect_event_source(event: Dict) -> str:
    if "Records" in event:
        records = event["Records"]
        if records:
            source = records[0].get("eventSource", records[0].get("EventSource", ""))
            if "sqs" in source.lower():
                return "SQS"
            elif "sns" in source.lower():
                return "SNS"
            elif "s3" in source.lower():
                return "S3"
            elif "dynamodb" in source.lower():
                return "DynamoDB_Streams"
    if "httpMethod" in event or "requestContext" in event:
        return "API_Gateway"
    if "source" in event and event["source"] == "aws.events":
        return "EventBridge"
    if "detail-type" in event:
        return "EventBridge"
    return "Direct_Invocation"


def _build_response(status_code: int, body: Any, headers: Optional[Dict] = None) -> Dict:
    default_headers = {
        "Content-Type": "application/json",
        "X-Service-Name": SERVICE_NAME,
        "X-Shared-Role": "true",
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET,POST,PUT,DELETE,OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type,Authorization"
    }
    if headers:
        default_headers.update(headers)

    return {
        "statusCode": status_code,
        "headers": default_headers,
        "body": json.dumps(body, default=str)
    }


def _build_error_response(status_code: int, message: str, request_id: str) -> Dict:
    return _build_response(status_code, {
        "error": True,
        "message": message,
        "request_id": request_id,
        "service": SERVICE_NAME,
        "timestamp": datetime.now(timezone.utc).isoformat()
    })


def _aws_error_to_http_status(error_code: str) -> int:
    error_map = {
        "AccessDeniedException": 403,
        "ResourceNotFoundException": 404,
        "ConditionalCheckFailedException": 409,
        "ProvisionedThroughputExceededException": 429,
        "ThrottlingException": 429,
        "ValidationException": 400,
        "NoSuchKey": 404,
        "NoSuchBucket": 404,
    }
    return error_map.get(error_code, 500)


