# EXAMPLE LAMBDA HANDLER
# This demonstrates one of the 10+ microservice functions using the
# shared IAM role and shared service classes.
#
# Each Lambda function in the architecture follows this same pattern,
# all referencing the single SharedLambdaExecutionRole.
# =========================================================================

# Initialize services outside handler for connection reuse across invocations
# All these services work because the shared IAM role grants the necessary permissions
dynamo_service = DynamoDBService()
s3_service = S3Service()
sns_service = SNSService()
sqs_service = SQSService()


@microservice_handler(service_name=SERVICE_NAME)
def lambda_handler(event: Dict, context) -> Dict:
    """
    Main Lambda handler demonstrating usage of all four AWS services
    (S3, DynamoDB, SNS, SQS) via the shared IAM role.

    Supports multiple event sources:
    - API Gateway (REST)
    - SQS triggers
    - SNS triggers
    - S3 event notifications
    - Direct invocation
    """
    event_source = _detect_event_source(event)
    request_id = getattr(context, "aws_request_id", "unknown")

    logger.info(f"Processing event from source: {event_source}")

    if event_source == "API_Gateway":
        return _handle_api_gateway_event(event, request_id)
    elif event_source == "SQS":
        return _handle_sqs_event(event, request_id)
    elif event_source == "SNS":
        return _handle_sns_event(event, request_id)
    elif event_source == "S3":
        return _handle_s3_event(event, request_id)
    else:
        return _handle_direct_invocation(event, request_id)


def _handle_api_gateway_event(event: Dict, request_id: str) -> Dict:
    """Handle API Gateway REST API events."""
    http_method = event.get("httpMethod", "GET")
    path = event.get("path", "/")
    path_params = event.get("pathParameters") or {}
    query_params = event.get("queryStringParameters") or {}

    body = {}
    if event.get("body"):
        try:
            body = json.loads(event["body"])
        except (json.JSONDecodeError, TypeError):
            return _build_response(400, {
                "error": True,
                "message": "Invalid JSON in request body"
            })

    # Route to appropriate handler
    if http_method == "GET" and "id" in path_params:
        return _get_item(path_params["id"], request_id)
    elif http_method == "POST":
        return _create_item(body, request_id)
    elif http_method == "PUT" and "id" in path_params:
        return _update_item(path_params["id"], body, request_id)
    elif http_method == "DELETE" and "id" in path_params:
        return _delete_item(path_params["id"], request_id)
    elif http_method == "GET":
        return _list_items(query_params, request_id)
    else:
        return _build_response(405, {"error": True, "message": "Method not allowed"})


def _get_item(item_id: str, request_id: str) -> Dict:
    """Retrieve an item from DynamoDB (uses SharedDynamoDBAccess)."""
    item = dynamo_service.get_item({"id": item_id})
    if not item:
        return _build_response(404, {
            "error": True,
            "message": f"Item {item_id} not found"
        })
    return _build_response(200, {
        "data": item,
        "request_id": request_id
    })


def _create_item(body: Dict, request_id: str) -> Dict:
    """
    Create a new item:
    1. Store in DynamoDB (SharedDynamoDBAccess)
    2. Optionally store attachment in S3 (SharedS3Access)
    3. Publish creation event to SNS (SharedSNSAccess)
    4. Enqueue follow-up processing in SQS (SharedSQSAccess)
    """
    if not body.get("id"):
        return _build_response(400, {
            "error": True,
            "message": "Field 'id' is required"
        })

    item = {
        "id": body["id"],
        "data": body.get("data", {}),
        "status": "active",
        "created_at": datetime.now(timezone.utc).isoformat(),
        "created_by": SERVICE_NAME,
        "request_id": request_id
    }

    # 1. Store in DynamoDB
    dynamo_service.put_item(item)
    logger.info(f"Item {body['id']} stored in DynamoDB")

    # 2. Store in S3 if there's an attachment
    if body.get("attachment"):
        s3_key = f"{SERVICE_NAME}/{body['id']}/attachment.json"
        s3_service.put_object(
            key=s3_key,
            body=json.dumps(body["attachment"]).encode("utf-8"),
            content_type="application/json",
            metadata={"item_id": body["id"], "service": SERVICE_NAME}
        )
        logger.info(f"Attachment stored in S3: {s3_key}")

    # 3. Publish event to SNS for other microservices
    if SNS_TOPIC_ARN:
        sns_service.publish(
            message={
                "event_type": "ITEM_CREATED",
                "item_id": body["id"],
                "service": SERVICE_NAME,
                "timestamp": datetime.now(timezone.utc).isoformat()
            },
            subject=f"{SERVICE_NAME}: Item Created"
        )
        logger.info(f"Creation event published to SNS")

    # 4. Enqueue for async processing
    if SQS_QUEUE_URL:
        sqs_service.send_message(
            message_body={
                "action": "POST_CREATE_PROCESSING",
                "item_id": body["id"],
                "service": SERVICE_NAME,
                "timestamp": datetime.now(timezone.utc).isoformat()
            }
        )
        logger.info(f"Follow-up task queued in SQS")

    return _build_response(201, {
        "message": "Item created successfully",
        "data": item,
        "request_id": request_id
    })


def _update_item(item_id: str, body: Dict, request_id: str) -> Dict:
    """Update an item in DynamoDB and notify via SNS."""
    from boto3.dynamodb.conditions import Attr

    update_fields = body.get("data", {})
    if not update_fields:
        return _build_response(400, {
            "error": True,
            "message": "No update data provided"
        })

    update_expr_parts = []
    expr_values = {}
    for idx, (key, value) in enumerate(update_fields.items()):
        placeholder = f":val{idx}"
        update_expr_parts.append(f"{key} = {placeholder}")
        expr_values[placeholder] = value

    # Always update the timestamp
    update_expr_parts.append("updated_at = :updated_at")
    expr_values[":updated_at"] = datetime.now(timezone.utc).isoformat()

    update_expression = "SET " + ", ".join(update_expr_parts)

    updated_item = dynamo_service.update_item(
        key={"id": item_id},
        update_expression=update_expression,
        expression_values=expr_values
    )

    # Notify about the update
    if SNS_TOPIC_ARN:
        sns_service.publish(
            message={
                "event_type": "ITEM_UPDATED",
                "item_id": item_id,
                "updated_fields": list(update_fields.keys()),
                "service": SERVICE_NAME,
                "timestamp": datetime.now(timezone.utc).isoformat()
            },
            subject=f"{SERVICE_NAME}: Item Updated"
        )

    return _build_response(200, {
        "message": "Item updated successfully",
        "data": updated_item,
        "request_id": request_id
    })


def _delete_item(item_id: str, request_id: str) -> Dict:
    """Delete item from DynamoDB and S3, notify via SNS."""
    # Delete from DynamoDB
    dynamo_service.delete_item({"id": item_id})

    # Clean up S3 objects
    if S3_BUCKET:
        prefix = f"{SERVICE_NAME}/{item_id}/"
        objects = s3_service.list_objects(prefix=prefix)
        for obj in objects:
            s3_service.delete_object(obj["Key"])
            logger.info(f"Deleted S3 object: {obj['Key']}")

    # Notify deletion
    if SNS_TOPIC_ARN:
        sns_service.publish(
            message={
                "event_type": "ITEM_DELETED",
                "item_id": item_id,
                "service": SERVICE_NAME,
                "timestamp": datetime.now(timezone.utc).isoformat()
            },
            subject=f"{SERVICE_NAME}: Item Deleted"
        )

    return _build_response(200, {
        "message": f"Item {item_id} deleted successfully",
        "request_id": request_id
    })


def _list_items(query_params: Dict, request_id: str) -> Dict:
    """List items - simplified for demonstration."""
    from boto3.dynamodb.conditions import Key

    status_filter = query_params.get("status", "active")
