def _handle_sqs_event(event: Dict, request_id: str) -> Dict:
    """
    Handle SQS trigger events (uses SharedSQSAccess for DLQ forwarding,
    SharedDynamoDBAccess for processing).
    """
    processed = 0
    failed = 0

    for record in event.get("Records", []):
        try:
            message_body = json.loads(record["body"])
            action = message_body.get("action", "UNKNOWN")

            logger.info(f"Processing SQS message: action={action}, messageId={record['messageId']}")

            if action == "POST_CREATE_PROCESSING":
                item_id = message_body.get("item_id")
                # Perform additional processing after item creation
                # e.g., generate thumbnails, calculate metrics, etc.
                dynamo_service.update_item(
                    key={"id": item_id},
                    update_expression="SET processing_status = :status, processed_at = :ts",
                    expression_values={
                        ":status": "processed",
                        ":ts": datetime.now(timezone.utc).isoformat()
                    }
                )
                logger.info(f"Post-create processing complete for item {item_id}")

            processed += 1
        except Exception as e:
            failed += 1
            logger.error(f"Failed to process SQS record: {str(e)}")
            # Re-raise to let Lambda retry via SQS visibility timeout
            raise

    return {"processed": processed, "failed": failed}


def _handle_sns_event(event: Dict, request_id: str) -> Dict:
    """
    Handle SNS trigger events - react to events from other microservices.
    All microservices can publish/subscribe using the SharedSNSAccess policy.
    """
    processed = 0

    for record in event.get("Records", []):
        sns_message = record.get("Sns", {})
        subject = sns_message.get("Subject", "")
        message = json.loads(sns_message.get("Message", "{}"))
        event_type = message.get("event_type", "UNKNOWN")

        logger.info(f"Processing SNS event: type={event_type}, subject={subject}")

        # React to events from other microservices
        source_service = message.get("service", "unknown")
        if source_service != SERVICE_NAME:
            # Cross-service event handling
            logger.info(f"Received event from {source_service}: {event_type}")

            # Log the cross-service event
            dynamo_service.put_item({
                "id": f"event-{request_id}-{processed}",
                "event_type": event_type,
                "source_service": source_service,
                "payload": message,
                "received_at": datetime.now(timezone.utc).isoformat()
            })

        processed += 1

    return {"processed": processed}


def _handle_s3_event(event: Dict, request_id: str) -> Dict:
    """
    Handle S3 event notifications.
    Uses SharedS3Access for reading objects, SharedDynamoDBAccess for metadata.
    """
    processed = 0

    for record in event.get("Records", []):
        s3_info = record.get("s3", {})
        bucket = s3_info.get("bucket", {}).get("name", "")
        key = s3_info.get("object", {}).get("key", "")
        event_name = record.get("eventName", "")

        logger.info(f"Processing S3 event: {event_name} for {bucket}/{key}")

        if "ObjectCreated" in event_name:
            # Read the new object and process it
            s3_client = S3Service(bucket_name=bucket)
            content = s3_client.get_object(key)

            # Store metadata in DynamoDB
            dynamo_service.put_item({
                "id": f"s3-event-{key.replace('/', '-')}",
                "bucket": bucket,
                "key": key,
                "size": s3_info.get("object", {}).get("size", 0),
                "event_type": event_name,
                "processed_at": datetime.now(timezone.utc).isoformat()
            })

            # Notify other services
            if SNS_TOPIC_ARN:
                sns_service.publish(
                    message={
                        "event_type": "S3_OBJECT_PROCESSED",
                        "bucket": bucket,
                        "key": key,
                        "service": SERVICE_NAME
                    },
                    subject=f"{SERVICE_NAME}: S3 Object Processed"
                )

        processed += 1

    return {"processed": processed}


def _handle_direct_invocation(event: Dict, request_id: str) -> Dict:
    """Handle direct Lambda invocations (from other Lambda functions, Step Functions, etc.)."""
    action = event.get("action", "health_check")

    if action == "health_check":
        return {
            "status": "healthy",
            "service": SERVICE_NAME,
            "environment": ENVIRONMENT,
            "shared_role": SHARED_ROLE_ARN,
            "timestamp": datetime.now(timezone.utc).isoformat(),
            "request_id": request_id,
            "capabilities": {
                "s3": bool(S3_BUCKET),
                "dynamodb": bool(DYNAMODB_TABLE),
                "sns": bool(SNS_TOPIC_ARN),
                "sqs": bool(SQS_QUEUE_URL)
            }
        }
    elif action == "process_batch":
        items = event.get("items", [])
        results = []
        for item in items:
            dynamo_service.put_item(item)
            results.append({"id": item.get("id"), "status": "stored"})
        return {"processed": len(results), "results": results}
    else:
        return {
            "message": f"Unknown action: {action}",
            "service": SERVICE_NAME,
            "request_id": request_id
        }


# =========================================================================
# IAM ROLE VALIDATION UTILITY
# Run this during deployment or as a health check to verify the shared role
# has all required permissions.
# =========================================================================
def validate_shared_role_permissions(event: Dict, context) -> Dict:
    """
    Utility function to validate that the shared IAM role has all
    required permissions. Can be invoked periodically or during deployment.
    """
    results = {
        "service": SERVICE_NAME,
        "role_arn": SHARED_ROLE_ARN,
        "timestamp": datetime.now(timezone.utc).isoformat(),
        "checks": {}
    }

    # Test DynamoDB access
    try:
        client = AWSClientFactory.get_client("dynamodb")
        client.describe_table(TableName=DYNAMODB_TABLE)
        results["checks"]["dynamodb"] = {"status": "PASS", "table": DYNAMODB_TABLE}
    except ClientError as e:
        results["checks"]["dynamodb"] = {
            "status": "FAIL",
            "error": e.response["Error"]["Message"]
        }
    except Exception as e:
        results["checks"]["dynamodb"] = {"status": "FAIL", "error": str(e)}

    # Test S3 access
    try:
        if S3_BUCKET:
            client = AWSClientFactory.get_client("s3")
            client.head_bucket(Bucket=S3_BUCKET)
            results["checks"]["s3"] = {"status": "PASS", "bucket": S3_BUCKET}
        else:
            results["checks"]["s3"] = {"status": "SKIP", "reason": "No bucket configured"}
    except ClientError as e:
        results["checks"]["s3"] = {
            "status": "FAIL",
            "error": e.response["Error"]["Message"]
        }
    except Exception as e:
        results["checks"]["s3"] = {"status": "FAIL", "error": str(e)}

    # Test SNS access
    try:
        if SNS_TOPIC_ARN:
            client = AWSClientFactory.get_client("sns")
            client.get_topic_attributes(TopicArn=SNS_TOPIC_ARN)
            results["checks"]["sns"] = {"status": "PASS", "topic": SNS_TOPIC_ARN}
        else:
            results["checks"]["sns"] = {"status": "SKIP", "reason": "No topic configured"}
    except ClientError as e:
        results["checks"]["sns"] = {
            "status": "FAIL",
            "error": e.response["Error"]["Message"]
        }
    except Exception as e:
        results["checks"]["sns"] = {"status": "FAIL", "error": str(e)}

    # Test SQS access
    try:
        if SQS_QUEUE_URL:
            client = AWSClientFactory.get_client("sqs")
            client.get_queue_attributes(
                QueueUrl=SQS_QUEUE_URL,
                AttributeNames=["QueueArn"]
            )
            results["checks"]["sqs"] = {"status": "PASS", "queue": SQS_QUEUE_URL}
        else:
            results["checks"]["sqs"] = {"status": "SKIP", "reason": "No queue configured"}
    except ClientError as e:
        results["checks"]["sqs"] = {
            "status": "FAIL",
            "error": e.response["Error"]["Message"]
        }
    except Exception as e:
        results["checks"]["sqs"] = {"status": "FAIL", "error": str(e)}

    # Overall status
    check_statuses = [c["status"] for c in results["checks"].values()]
    if "FAIL" in check_statuses:
        results["overall_status"] = "UNHEALTHY"
    else:
        results["overall_status"] = "HEALTHY"

    logger.info(json.dumps(results, default=str))
    return results